import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import TrustBadge from '../components/TrustBadge';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [actionId, setActionId] = useState(null);
  const [successMsg, setSuccessMsg] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState({ total: 0, totalRaised: 0, totalGoal: 0, avgProgress: 0 });

  const fetchAllCampaigns = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await axios.get('/api/campaigns/admin/all');
      const list = data.campaigns;
      setCampaigns(list);

      const totalRaised = list.reduce((a, c) => a + c.raised, 0);
      const totalGoal = list.reduce((a, c) => a + c.goal, 0);
      const avgProgress = totalGoal > 0 ? Math.round((totalRaised / totalGoal) * 100) : 0;
      setStats({ total: list.length, totalRaised, totalGoal, avgProgress });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load campaigns.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchAllCampaigns(); }, [fetchAllCampaigns]);

  const handleDelete = async (id, title) => {
    if (!window.confirm(`Permanently delete "${title}"? This cannot be undone.`)) return;
    try {
      setActionId(id);
      setError('');
      setSuccessMsg('');
      await axios.delete(`/api/campaigns/${id}`);
      setCampaigns((prev) => prev.filter((c) => c._id !== id));
      setStats((prev) => ({ ...prev, total: prev.total - 1 }));
      setSuccessMsg(`"${title}" was deleted successfully.`);
      setTimeout(() => setSuccessMsg(''), 5000);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to delete campaign.');
      setTimeout(() => setError(''), 5000);
    } finally {
      setActionId(null);
    }
  };

  const handleVerify = async (id, title) => {
    if (!window.confirm(`Mark "${title}" as verified? This adds +50 to trust score.`)) return;
    try {
      setActionId(id);
      setError('');
      setSuccessMsg('');
      const { data } = await axios.patch(`/api/campaigns/admin/verify/${id}`);
      setCampaigns((prev) => prev.map((c) => c._id === id ? data.campaign : c));
      setSuccessMsg(`"${title}" is now verified.`);
      setTimeout(() => setSuccessMsg(''), 5000);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to verify campaign.');
      setTimeout(() => setError(''), 5000);
    } finally {
      setActionId(null);
    }
  };

  const filtered = campaigns.filter((c) => {
    const q = searchTerm.toLowerCase();
    return (
      c.title.toLowerCase().includes(q) ||
      c.category.toLowerCase().includes(q) ||
      (c.creator?.name || '').toLowerCase().includes(q)
    );
  });

  return (
    <div className="admin-page">
      <div className="container">

        {/* Header */}
        <div className="admin-header" id="admin-header">
          <div className="admin-header-text">
            <h1>⚙️ Admin Dashboard</h1>
            <p>Manage verifications and monitor all FundIt campaigns in one place.</p>
          </div>
          <Link to="/create-campaign" className="btn btn-primary btn-sm" id="admin-create-btn">
            + New Campaign
          </Link>
        </div>

        {/* Stats */}
        <div className="admin-stats" id="admin-stats">
          <div className="stat-card" id="stat-total">
            <div className="stat-icon">📋</div>
            <div className="stat-value">{stats.total}</div>
            <div className="stat-label">Total Campaigns</div>
          </div>
          <div className="stat-card" id="stat-raised">
            <div className="stat-icon">💰</div>
            <div className="stat-value" style={{ color: 'var(--green)' }}>
              ₹{stats.totalRaised >= 100000
                ? (stats.totalRaised / 100000).toFixed(1) + 'L'
                : stats.totalRaised.toLocaleString('en-IN')}
            </div>
            <div className="stat-label">Total Raised</div>
          </div>
          <div className="stat-card" id="stat-goal">
            <div className="stat-icon">🎯</div>
            <div className="stat-value">
              ₹{stats.totalGoal >= 100000
                ? (stats.totalGoal / 100000).toFixed(1) + 'L'
                : stats.totalGoal.toLocaleString('en-IN')}
            </div>
            <div className="stat-label">Combined Goal</div>
          </div>
          <div className="stat-card" id="stat-progress">
            <div className="stat-icon">📈</div>
            <div className="stat-value" style={{ color: 'var(--amber)' }}>{stats.avgProgress}%</div>
            <div className="stat-label">Overall Progress</div>
          </div>
        </div>

        {/* Alerts */}
        <div className="admin-alerts">
          {successMsg && (
            <div className="alert alert-success" id="admin-success-alert" role="alert">
              <span>✅</span><p>{successMsg}</p>
            </div>
          )}
          {error && (
            <div className="alert alert-error" id="admin-error-alert" role="alert">
              <span>⚠️</span>
              <p>{error} <button className="btn btn-sm btn-secondary" onClick={fetchAllCampaigns} style={{marginLeft:'0.5rem'}}>Retry</button></p>
            </div>
          )}
        </div>

        {/* Controls */}
        {!loading && (
          <div className="admin-controls" id="admin-controls">
            <div className="admin-search-box">
              <span className="admin-search-icon">🔍</span>
              <input
                type="text"
                id="admin-search"
                className="admin-search-input"
                placeholder="Search by title, category, creator..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                aria-label="Search admin campaigns"
              />
            </div>
            <span className="admin-results-count">
              {filtered.length} of {campaigns.length} campaigns
            </span>
          </div>
        )}

        {/* Table */}
        <div className="admin-table-card" id="admin-table-card">
          {loading ? (
            <div className="loading-state">
              <div className="spinner spinner-lg" />
              <p>Loading all campaigns...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div className="empty-state" id="admin-empty">
              <div style={{ fontSize: '2.5rem', marginBottom: '0.75rem' }}>📋</div>
              <h3>{searchTerm ? 'No matching campaigns' : 'No campaigns yet'}</h3>
              <p>{searchTerm ? 'Try a different search term.' : 'Create the first campaign to get started.'}</p>
            </div>
          ) : (
            <div className="table-scroll">
              <table className="data-table" id="campaigns-admin-table">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Campaign Title</th>
                    <th>Creator</th>
                    <th>Trust Score</th>
                    <th>Funded</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((c, i) => {
                    const pct = Math.min(Math.round((c.raised / c.goal) * 100), 100);
                    const funded = c.raised >= c.goal;
                    return (
                      <tr key={c._id} id={`admin-row-${c._id}`}>
                        <td style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>{i + 1}</td>
                        <td>
                          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.2rem' }}>
                            <Link to={`/campaigns/${c._id}`} className="campaign-link-cell" title={c.title}>
                              {c.title}
                            </Link>
                            <span className="badge badge-blue" style={{ alignSelf: 'flex-start', fontSize: '0.65rem', padding: '0.15rem 0.4rem' }}>
                              {c.category}
                            </span>
                          </div>
                        </td>
                        <td style={{ fontSize: '0.83rem', color: 'var(--text-secondary)' }}>
                          {c.creator?.name || 'N/A'}
                        </td>
                        <td>
                          <TrustBadge score={c.trustScore || 0} size="sm" />
                        </td>
                        <td>
                          <div className="progress-cell" style={{ flexDirection: 'column', alignItems: 'flex-start', gap: '0.2rem' }}>
                            <div style={{ fontWeight: 700, color: 'var(--green)', fontSize: '0.875rem' }}>₹{c.raised.toLocaleString('en-IN')}</div>
                            <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', width: '100px' }}>
                              <div className="progress-bar-wrapper" style={{ height: '4px', flex: 1 }}>
                                <div className="progress-bar-fill" style={{ width: `${pct}%` }} />
                              </div>
                              <span className="progress-cell-pct" style={{ fontSize: '0.7rem' }}>{pct}%</span>
                            </div>
                          </div>
                        </td>
                        <td>
                          {funded
                            ? <span className="badge badge-green">✓ Funded</span>
                            : c.isActive
                              ? <span className="badge badge-blue">Active</span>
                              : <span className="badge" style={{ background: '#f1f5f9', color: 'var(--text-muted)', border: '1px solid var(--border)' }}>Inactive</span>
                          }
                          {c.isVerified && <div style={{ fontSize: '0.7rem', color: '#15803d', marginTop: '0.2rem', fontWeight: 600 }}>✅ Verified</div>}
                        </td>
                        <td>
                          <div className="action-cell">
                            {!c.isVerified && (
                              <button
                                className="btn btn-secondary btn-sm"
                                style={{ background: '#dcfce7', color: '#15803d', borderColor: '#bbf7d0' }}
                                onClick={() => handleVerify(c._id, c.title)}
                                disabled={actionId === c._id}
                              >
                                {actionId === c._id ? '...' : 'Verify'}
                              </button>
                            )}
                            <button
                              className="btn btn-danger btn-sm"
                              onClick={() => handleDelete(c._id, c.title)}
                              disabled={actionId === c._id}
                            >
                              Delete
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
